import{_ as n,o as a,c as l,a2 as o}from"./chunks/framework.B72_uj9U.js";const d=JSON.parse('{"title":"Environment Variables","description":"Control the environment variable inheritance and injection for spawned processes to ensure consistent and secure execution contexts.","frontmatter":{"title":"Environment Variables","description":"Control the environment variable inheritance and injection for spawned processes to ensure consistent and secure execution contexts."},"headers":[],"relativePath":"learn/project/06-shell-execution/06-environment-variables.md","filePath":"learn/project/06-shell-execution/06-environment-variables.md"}'),t={name:"learn/project/06-shell-execution/06-environment-variables.md"};function e(p,s,c,r,i,y){return a(),l("div",null,[...s[0]||(s[0]=[o(`<h1 id="environment-variables" tabindex="-1">Environment Variables <a class="header-anchor" href="#environment-variables" aria-label="Permalink to &quot;Environment Variables&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>How to inherit, override, and clear environment variables for child processes</li><li>How to inject tool-specific variables like API keys or configuration paths</li><li>How to prevent sensitive environment variable leakage across process boundaries</li></ul></blockquote><p>When your agent runs <code>cargo test</code> or <code>npm run build</code>, those commands depend on environment variables like <code>PATH</code>, <code>HOME</code>, <code>CARGO_HOME</code>, and <code>NODE_ENV</code>. Getting the environment right is the difference between commands that work and commands that fail mysteriously. But you also need to be careful: your agent process might have API keys or tokens in its environment that you do not want leaking into arbitrary shell commands.</p><h2 id="how-environment-inheritance-works" tabindex="-1">How Environment Inheritance Works <a class="header-anchor" href="#how-environment-inheritance-works" aria-label="Permalink to &quot;How Environment Inheritance Works&quot;">​</a></h2><p>By default, a child process inherits the full environment of its parent. This means that when your Rust agent spawns <code>sh -c &quot;echo $HOME&quot;</code>, the child sees the same <code>HOME</code>, <code>PATH</code>, <code>USER</code>, and every other variable that your agent process has:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> tokio</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">process</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Command</span><span style="color:#CBA6F7;"> as</span><span style="color:#F9E2AF;font-style:italic;"> TokioCommand</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">tokio</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">main</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CBA6F7;">async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Child inherits all of the parent&#39;s environment variables</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> output </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> TokioCommand</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;sh&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">arg</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;-c&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">arg</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;echo HOME=$HOME &amp;&amp; echo PATH=$PATH&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">output</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#CBA6F7;">await</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">expect</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;failed to execute&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from_utf8_lossy</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">output</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">stdout</span><span style="color:#9399B2;">));</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>This default is convenient -- most commands just work. But it is a security concern for an agent that holds sensitive credentials.</p><h2 id="adding-and-overriding-variables" tabindex="-1">Adding and Overriding Variables <a class="header-anchor" href="#adding-and-overriding-variables" aria-label="Permalink to &quot;Adding and Overriding Variables&quot;">​</a></h2><p>The <code>.env()</code> method on <code>Command</code> adds or overrides a single environment variable without affecting the rest:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> tokio</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">process</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Command</span><span style="color:#CBA6F7;"> as</span><span style="color:#F9E2AF;font-style:italic;"> TokioCommand</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">tokio</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">main</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CBA6F7;">async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> output </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> TokioCommand</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;sh&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">arg</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;-c&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">arg</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;echo GREETING=$GREETING &amp;&amp; echo HOME=$HOME&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">env</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;GREETING&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;hello from the agent&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">output</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#CBA6F7;">await</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">expect</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;failed to execute&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from_utf8_lossy</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">output</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">stdout</span><span style="color:#9399B2;">));</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Output:</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // GREETING=hello from the agent</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // HOME=/Users/yourname      (inherited from parent)</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The child sees <code>GREETING</code> (which you set) and <code>HOME</code> (which it inherited). This additive approach is what you want most of the time.</p><p>You can also pass multiple variables using <code>.envs()</code> with an iterator of key-value pairs:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">collections</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">HashMap</span><span style="color:#9399B2;">;</span></span>
<span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> tokio</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">process</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Command</span><span style="color:#CBA6F7;"> as</span><span style="color:#F9E2AF;font-style:italic;"> TokioCommand</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">tokio</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">main</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CBA6F7;">async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CBA6F7;"> mut</span><span style="color:#CDD6F4;"> extra_vars </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> HashMap</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#CDD6F4;">    extra_vars</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">insert</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;NODE_ENV&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;test&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#CDD6F4;">    extra_vars</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">insert</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;CI&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;true&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#CDD6F4;">    extra_vars</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">insert</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;RUST_LOG&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;debug&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> output </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> TokioCommand</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;sh&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">arg</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;-c&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">arg</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;echo NODE_ENV=$NODE_ENV CI=$CI RUST_LOG=$RUST_LOG&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">envs</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">extra_vars</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">output</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#CBA6F7;">await</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">expect</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;failed to execute&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from_utf8_lossy</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">output</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">stdout</span><span style="color:#9399B2;">));</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>Python&#39;s <code>subprocess.run()</code> takes an <code>env</code> parameter that <strong>replaces</strong> the entire environment:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> os</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> subprocess</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># This REPLACES the environment -- PATH is gone!</span></span>
<span class="line"><span style="color:#CDD6F4;">result </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> subprocess</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">run</span><span style="color:#9399B2;">([</span><span style="color:#A6E3A1;">&quot;echo&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;hello&quot;</span><span style="color:#9399B2;">],</span><span style="color:#EBA0AC;font-style:italic;"> env</span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;">{</span><span style="color:#A6E3A1;">&quot;MY_VAR&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;value&quot;</span><span style="color:#9399B2;">})</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># To add variables, you must merge with os.environ:</span></span>
<span class="line"><span style="color:#CDD6F4;">env </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> {</span><span style="color:#94E2D5;">**</span><span style="color:#CDD6F4;">os</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">environ</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;MY_VAR&quot;</span><span style="color:#9399B2;">:</span><span style="color:#A6E3A1;"> &quot;value&quot;</span><span style="color:#9399B2;">}</span></span>
<span class="line"><span style="color:#CDD6F4;">result </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> subprocess</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">run</span><span style="color:#9399B2;">([</span><span style="color:#A6E3A1;">&quot;echo&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;hello&quot;</span><span style="color:#9399B2;">],</span><span style="color:#EBA0AC;font-style:italic;"> env</span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;">env</span><span style="color:#9399B2;">)</span></span></code></pre></div><p>Rust&#39;s <code>.env()</code> method is additive by default -- it adds to the inherited environment without removing anything. To get the &quot;replace everything&quot; behavior from Python, you call <code>.env_clear()</code> first, then add only the variables you want.</p></div><h2 id="clearing-the-environment" tabindex="-1">Clearing the Environment <a class="header-anchor" href="#clearing-the-environment" aria-label="Permalink to &quot;Clearing the Environment&quot;">​</a></h2><p>For maximum isolation, you can clear the entire inherited environment and build from scratch:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> tokio</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">process</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Command</span><span style="color:#CBA6F7;"> as</span><span style="color:#F9E2AF;font-style:italic;"> TokioCommand</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">tokio</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">main</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CBA6F7;">async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> output </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> TokioCommand</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;sh&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">arg</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;-c&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">arg</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;echo HOME=$HOME PATH=$PATH MY_VAR=$MY_VAR&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">env_clear</span><span style="color:#9399B2;">()</span><span style="color:#6C7086;font-style:italic;">                       // Remove ALL inherited variables</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">env</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;PATH&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;/usr/bin:/bin&quot;</span><span style="color:#9399B2;">)</span><span style="color:#6C7086;font-style:italic;">      // Add back only what we need</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">env</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;HOME&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;/tmp&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">env</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;MY_VAR&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;isolated&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">output</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#CBA6F7;">await</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">expect</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;failed to execute&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from_utf8_lossy</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">output</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">stdout</span><span style="color:#9399B2;">));</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Output: HOME=/tmp PATH=/usr/bin:/bin MY_VAR=isolated</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>After <code>.env_clear()</code>, the child has <strong>no</strong> environment variables at all, not even <code>PATH</code>. You must add back at least <code>PATH</code> for the shell to find executables, and <code>HOME</code> for programs that need it.</p><h2 id="removing-specific-variables" tabindex="-1">Removing Specific Variables <a class="header-anchor" href="#removing-specific-variables" aria-label="Permalink to &quot;Removing Specific Variables&quot;">​</a></h2><p>Sometimes you want to inherit everything <em>except</em> certain sensitive variables. The <code>.env_remove()</code> method selectively removes individual variables:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> tokio</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">process</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Command</span><span style="color:#CBA6F7;"> as</span><span style="color:#F9E2AF;font-style:italic;"> TokioCommand</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">tokio</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">main</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#CBA6F7;">async</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> main</span><span style="color:#9399B2;">()</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Suppose your agent has these set</span></span>
<span class="line"><span style="color:#F9E2AF;">    std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">env</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">set_var</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;ANTHROPIC_API_KEY&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;sk-secret-key-12345&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#F9E2AF;">    std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">env</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">set_var</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;DATABASE_URL&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;postgres://secret@localhost/db&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">    let</span><span style="color:#CDD6F4;"> output </span><span style="color:#94E2D5;">=</span><span style="color:#F9E2AF;font-style:italic;"> TokioCommand</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;sh&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">arg</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;-c&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">arg</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;echo KEY=$ANTHROPIC_API_KEY DB=$DATABASE_URL HOME=$HOME&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">env_remove</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;ANTHROPIC_API_KEY&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">env_remove</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;DATABASE_URL&quot;</span><span style="color:#9399B2;">)</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">output</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#CBA6F7;">await</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">expect</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;failed to execute&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89B4FA;font-style:italic;">    println!</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">from_utf8_lossy</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CDD6F4;">output</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;">stdout</span><span style="color:#9399B2;">));</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    // Output: KEY= DB= HOME=/Users/yourname</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>The sensitive variables are removed, but everything else (like <code>HOME</code> and <code>PATH</code>) is still inherited.</p><h2 id="building-an-environment-policy" tabindex="-1">Building an Environment Policy <a class="header-anchor" href="#building-an-environment-policy" aria-label="Permalink to &quot;Building an Environment Policy&quot;">​</a></h2><p>For your agent, you want a systematic approach to environment management. Here is a policy struct that defines which variables to keep, remove, and inject:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">collections</span><span style="color:#94E2D5;">::</span><span style="color:#9399B2;">{</span><span style="color:#F9E2AF;font-style:italic;">HashMap</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> HashSet</span><span style="color:#9399B2;">};</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">/// Policy for environment variable handling in shell commands.</span></span>
<span class="line"><span style="color:#F9E2AF;font-style:italic;">#</span><span style="color:#9399B2;">[</span><span style="color:#F9E2AF;font-style:italic;">derive</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">Debug</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> Clone</span><span style="color:#9399B2;">)]</span></span>
<span class="line"><span style="color:#CBA6F7;">pub</span><span style="color:#CBA6F7;"> struct</span><span style="color:#F9E2AF;font-style:italic;"> EnvPolicy</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    /// Variables to always remove from the inherited environment.</span></span>
<span class="line"><span style="color:#CDD6F4;">    sensitive_vars</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> HashSet</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">String</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    /// Variables to always inject into the child environment.</span></span>
<span class="line"><span style="color:#CDD6F4;">    injected_vars</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> HashMap</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">String</span><span style="color:#9399B2;">,</span><span style="color:#F9E2AF;font-style:italic;"> String</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    /// Whether to inherit the parent environment (after removing sensitive vars).</span></span>
<span class="line"><span style="color:#CDD6F4;">    inherit</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> bool</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">impl</span><span style="color:#F9E2AF;font-style:italic;"> Default</span><span style="color:#CBA6F7;"> for</span><span style="color:#F9E2AF;font-style:italic;"> EnvPolicy</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    fn</span><span style="color:#89B4FA;font-style:italic;"> default</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F38BA8;"> Self</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CDD6F4;"> sensitive </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> [</span></span>
<span class="line"><span style="color:#A6E3A1;">            &quot;ANTHROPIC_API_KEY&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">            &quot;OPENAI_API_KEY&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">            &quot;AWS_SECRET_ACCESS_KEY&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">            &quot;DATABASE_URL&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">            &quot;GITHUB_TOKEN&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#A6E3A1;">            &quot;SSH_AUTH_SOCK&quot;</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">        ]</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">iter</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">map</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;">s</span><span style="color:#94E2D5;">|</span><span style="color:#CDD6F4;"> s</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">to_string</span><span style="color:#9399B2;">())</span></span>
<span class="line"><span style="color:#94E2D5;">        .</span><span style="color:#89B4FA;font-style:italic;">collect</span><span style="color:#9399B2;">();</span></span>
<span class="line"></span>
<span class="line"><span style="color:#F38BA8;">        Self</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">            sensitive_vars</span><span style="color:#94E2D5;">:</span><span style="color:#CDD6F4;"> sensitive</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#CDD6F4;">            injected_vars</span><span style="color:#94E2D5;">:</span><span style="color:#F9E2AF;font-style:italic;"> HashMap</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">new</span><span style="color:#9399B2;">(),</span></span>
<span class="line"><span style="color:#CDD6F4;">            inherit</span><span style="color:#94E2D5;">:</span><span style="color:#F38BA8;"> true</span><span style="color:#9399B2;">,</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CBA6F7;">impl</span><span style="color:#F9E2AF;font-style:italic;"> EnvPolicy</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    /// Add a variable to the sensitive list (will be removed from child env).</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> add_sensitive</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CBA6F7;">mut</span><span style="color:#F38BA8;"> self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;"> var</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> impl</span><span style="color:#F9E2AF;font-style:italic;"> Into</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">String</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F38BA8;">        self</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">sensitive_vars</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">insert</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">var</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">into</span><span style="color:#9399B2;">());</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    /// Add a variable to inject into every child process.</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> inject</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CBA6F7;">mut</span><span style="color:#F38BA8;"> self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;"> key</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> impl</span><span style="color:#F9E2AF;font-style:italic;"> Into</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">String</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;"> value</span><span style="color:#94E2D5;">:</span><span style="color:#CBA6F7;"> impl</span><span style="color:#F9E2AF;font-style:italic;"> Into</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">String</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#F38BA8;">        self</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">injected_vars</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">insert</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">key</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">into</span><span style="color:#9399B2;">(),</span><span style="color:#CDD6F4;"> value</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">into</span><span style="color:#9399B2;">());</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">    /// Apply this policy to a tokio Command.</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> apply</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;"> cmd</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#CBA6F7;">mut</span><span style="color:#F9E2AF;"> tokio</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">process</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">Command</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">        if</span><span style="color:#94E2D5;"> !</span><span style="color:#F38BA8;">self</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">inherit </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CDD6F4;">            cmd</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">env_clear</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">            // At minimum, restore PATH so commands can be found</span></span>
<span class="line"><span style="color:#CBA6F7;">            if</span><span style="color:#CBA6F7;"> let</span><span style="color:#F9E2AF;font-style:italic;"> Ok</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">path</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =</span><span style="color:#F9E2AF;"> std</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">env</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">var</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;PATH&quot;</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CDD6F4;">                cmd</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">env</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;PATH&quot;</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> path</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">            }</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        // Remove sensitive variables</span></span>
<span class="line"><span style="color:#CBA6F7;">        for</span><span style="color:#CDD6F4;"> var </span><span style="color:#CBA6F7;">in</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F38BA8;">self</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">sensitive_vars </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CDD6F4;">            cmd</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">env_remove</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">var</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">        // Inject configured variables</span></span>
<span class="line"><span style="color:#CBA6F7;">        for</span><span style="color:#9399B2;"> (</span><span style="color:#CDD6F4;">key</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> value</span><span style="color:#9399B2;">)</span><span style="color:#CBA6F7;"> in</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F38BA8;">self</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">injected_vars </span><span style="color:#9399B2;">{</span></span>
<span class="line"><span style="color:#CDD6F4;">            cmd</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">env</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">key</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> value</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#9399B2;">        }</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Use the policy in your <code>ShellCommand</code> builder&#39;s <code>build()</code> method:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">impl</span><span style="color:#F9E2AF;font-style:italic;"> ShellCommand</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    pub</span><span style="color:#CBA6F7;"> fn</span><span style="color:#89B4FA;font-style:italic;"> build_with_policy</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;"> policy</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">EnvPolicy</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> TokioCommand</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CBA6F7;"> mut</span><span style="color:#CDD6F4;"> cmd </span><span style="color:#94E2D5;">=</span><span style="color:#F38BA8;"> self</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">build</span><span style="color:#9399B2;">();</span></span>
<span class="line"><span style="color:#CDD6F4;">        policy</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">apply</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#CBA6F7;">mut</span><span style="color:#CDD6F4;"> cmd</span><span style="color:#9399B2;">);</span></span>
<span class="line"><span style="color:#CDD6F4;">        cmd</span></span>
<span class="line"><span style="color:#9399B2;">    }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span></code></pre></div><p>Now every command your agent runs automatically strips API keys and other secrets from the child&#39;s environment, without the caller needing to remember to do it.</p><h2 id="common-environment-variables-for-coding-agents" tabindex="-1">Common Environment Variables for Coding Agents <a class="header-anchor" href="#common-environment-variables-for-coding-agents" aria-label="Permalink to &quot;Common Environment Variables for Coding Agents&quot;">​</a></h2><p>Here are environment variables you will frequently interact with:</p><table tabindex="0"><thead><tr><th>Variable</th><th>Purpose</th><th>Agent Consideration</th></tr></thead><tbody><tr><td><code>PATH</code></td><td>Where to find executables</td><td>Must be inherited or the child cannot run anything</td></tr><tr><td><code>HOME</code></td><td>User&#39;s home directory</td><td>Needed for tools that use <code>~/.config</code></td></tr><tr><td><code>TERM</code></td><td>Terminal type</td><td>Set to <code>dumb</code> to disable color codes in output</td></tr><tr><td><code>CI</code></td><td>Continuous integration flag</td><td>Set to <code>true</code> to make tools produce non-interactive output</td></tr><tr><td><code>RUST_BACKTRACE</code></td><td>Rust backtrace control</td><td>Set to <code>1</code> for debugging failed commands</td></tr><tr><td><code>NO_COLOR</code></td><td>Disable color output</td><td>Set to <code>1</code> for clean, parseable output</td></tr></tbody></table><p>For an agent, setting <code>TERM=dumb</code> and <code>NO_COLOR=1</code> is often helpful because it prevents commands from emitting ANSI color codes that clutter the output sent to the LLM.</p><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>Claude Code strips sensitive environment variables (API keys, tokens) before passing the environment to child processes. It also injects <code>CI=true</code> and <code>TERM=dumb</code> to encourage non-interactive, color-free output from build tools and test runners. This produces cleaner output that is easier for the LLM to parse and reason about.</p></div><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Child processes inherit the parent&#39;s full environment by default. Use <code>.env()</code> to add variables and <code>.env_remove()</code> to remove specific ones.</li><li>Always strip sensitive variables (API keys, database credentials, tokens) from the child environment to prevent leakage.</li><li>Create an <code>EnvPolicy</code> struct to systematically manage environment variables across all shell commands your agent executes.</li><li>Set <code>TERM=dumb</code> and <code>NO_COLOR=1</code> to get clean, color-free output that is easier for the LLM to process.</li><li>Use <code>.env_clear()</code> sparingly -- it removes everything including <code>PATH</code>, which will break most commands.</li></ul>`,35)])])}const B=n(t,[["render",e]]);export{d as __pageData,B as default};
